import { Card, Button } from '@nextui-org/react';

const ProjectCard = ({ title, description, link }) => {
  return (
    <Card shadow>
      <h3>{title}</h3>
      <p>{description}</p>
      <Button auto>Ver proyecto</Button>
    </Card>
  );
};

export default ProjectCard;
